parameters.jsCode:
const data = $input.first().json.output;

const parts = new Intl.DateTimeFormat('en-GB', {
  timeZone: 'Australia/Brisbane',
  day: '2-digit',
  month: '2-digit',
  year: 'numeric',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit',
  hourCycle: 'h23'
}).formatToParts(new Date());

const get = (type) => parts.find(p => p.type === type)?.value || '';

const timestamp = `${get('day')}/${get('month')}/${get('year')}, ${get('hour')}:${get('minute')}:${get('second')}`;

return [
  {
    json: {
      Timestamp: timestamp,
      id: data.id,
      "Lead Type": "Google Ads Lead",
      "First Name": data.first_name,
      "Last Name": data.last_name,
      "Mobile Number": data.mobile_number,
      "Phone Number": data.phone_number,
      "Email Address": data.email_address,
      "Address": data.address,
      "State": data.state,
      "Suburb": data.suburb,
      "Postal Code": data.postal_code,
      "Enquiry": data.message,
      "Quantity": data.quantity,
      "IdLikeToGetMyProjectUnderway": data.IdLikeToGetMyProjectUnderway,
      "How they heard about us": "Google",
      "Lead Qualifier": "Good"
    }
  }
];

